\section*{49. Homomorphismes de $M_{0,3}$, les groupes $M_{g,\nu}$ généraux}\marginpar{\footnotesize 550}

\textbf{I)} Considérons un sous-groupe [unclear: fermé] $\mathcal{G}$ de $M_{0,3}$, contenant $\mathfrak{S}^{+\wedge}_{0,3}$, donc image inverse d'un sous-groupe fermé de $\Gamma_{0,\widetilde{3}}$.\footnote{\footnotesize Tout ce qui suit est purement [unclear: catégorique] et s'applique \emph{verbatim} à des [unclear: situations] plus [unclear: générales] des [unclear: théories] de [unclear: déformations].} On suppose que celui-ci est ``suffisamment gros'' --- disons qu'il contient un sous-groupe d'indice fini de $\Gamma_{\mathbf{Q}} \subset \Gamma_{0,\widetilde{3}}$. Pour les [unclear: raisonnements], on supposera pour simplifier que
$$
\mathfrak{S}^{+\wedge}_{0,3} \subset \mathcal{G} \subset M_{0,\widetilde{3}}, \quad \mathrm{et}~\mathcal{G} \Rightarrow \mu(\mathcal{G}) \equiv 1~(3) \leqno{(1)}
$$
Cette dernière hypothèse signifie donc que pour tout $u \in \mathcal{G}$, on a $x_0 \in \mathfrak{S}^{+\wedge}_{0,3}$, donc on a
$$
\mathcal{G} \xrightarrow{\overset{x_0}{\underset{\beta_0}{\rightrightarrows}}} \mathfrak{S}^{+\wedge}_{0,3}, \leqno{(2)}
$$
ou restrictions pour
$$
\begin{cases} u(\rho) = \operatorname{int}(\alpha_u)\rho \\ u(\sigma) = \operatorname{int}(\beta_u)\sigma \end{cases} \qquad \alpha_0 = x_0\, \mathrm{lois} \qquad \beta_0 = \beta_0\, \mathrm{lois}. \leqno{(2')}
$$
On considère
$$
\begin{aligned} \mathcal{G}(\cdot) &= \mathcal{G} \cap M_{0,\widetilde{3}}(\cdot) \\ \mathcal{G}[\cdot] &= \mathcal{G} \cap M_{0,\widetilde{3}}[\cdot] = \operatorname{Norm}_{\mathcal{G}}(L_0^{\mathcal{B}}) \end{aligned} \leqno{(3)}
$$
de sorte que
\begin{align*}
\mathcal{G} &= \mathcal{G}(\cdot) \cdot \mathfrak{S}^{+\wedge}_{0,3} \quad (\text{[unclear: produit semi-direct]}) \tag{4} \\
\mathcal{G}[\cdot] &= \mathcal{G}(\cdot) \cdot L_0^{\mathcal{B}} \tag{5} \\
\mathcal{G}[\cdot] \cap \mathfrak{S}^{+\wedge}_{0,3} &= L_0^{\mathcal{B}} \tag{6}
\end{align*}
On a posé
$$
L_0^{\mathcal{B}} = \text{sous-groupe fermé de } \mathfrak{S}^{+\wedge}_{0,3} \text{ engendré} \leqno{(7)}
$$
et on dispose de même pour $z_0$: $L_1^{\mathcal{B}}, L_\infty^{\mathcal{B}}$.

\chapter*{\S\space 49. --- Homomorphismes de $\mathcal{M}_{0,3}$, les groupes $\mathcal{M}_{g,\nu}$ généraux}
\addcontentsline{toc}{section}{49. Homomorphismes de $\mathcal{M}_{0,3}$, les groupes $\mathcal{M}_{g,\nu}$ généraux}
\label{sec:49}
\section*{}

\textbf{I)} Considérons un sous-groupe fermé $\mathcal{G}$ de $\mathcal{M}_{0,3}$, contenant $\mathfrak{S}^{+\wedge}_{0,3}$, donc image inverse d'un sous-groupe fermé de $\widetilde{\Gamma}_{0,3}$. On suppose que celui-ci est « suffisamment gros » --- disons qu'il contient un sous-groupe d'indice fini de $\Gamma_{\mathbf{Q}} \subset \widetilde{\Gamma}_{0,3}$. Pour le moment, on supposera pour simplifier que\footnote{Tout cela s'applique en fait aussi au cas où on se borne à supposer que $\mathcal{G}$ contient un sous-groupe d'indice fini de $\Gamma_{\mathbf{Q}}$, modulo les modifications évidentes.}
$$
\mathcal{G} \subset \Ker \varepsilon_3. \text{ En résumé :}
$$
$$
\mathfrak{S}^{+\wedge}_{0,3} \subset \mathcal{G} \subset \mathcal{M}_{0,3}^{\sim}, \quad u \in \mathcal{G} \implies \mu(u) \equiv 1 \,(3) \leqno{(1)}
$$
Cette dernière hypothèse signifie donc que pour tout $u \in \mathcal{G}$, on a $\alpha_0^{u} \in \mathfrak{S}^{+\wedge}_{0,3}$, donc on a
$$
\mathcal{G} \xrightrightarrows[\beta_0]{\alpha_0} \mathfrak{S}^{+\wedge}_{0,3}, \leqno{(2)}
$$
compatibles par
$$
\begin{cases} u(\rho) = \operatorname{int}(\alpha_0) \rho \\ u(\sigma) = \operatorname{int}(\beta_0) \sigma \end{cases} \qquad \alpha_0 = \alpha_0(u), \quad \beta_0 = \beta_0(u). \leqno{(2')}
$$

On considère
$$
\begin{aligned}
\mathcal{G}(0) &= \mathcal{G} \cap \mathcal{M}_{0,3}^{\sim}(0) \\
\mathcal{G}[0] &= \mathcal{G} \cap \mathcal{M}_{0,3}^{\sim}[0] = \operatorname{Norm}_{\mathcal{G}}(L_0^{\mathbb{C}})
\end{aligned} \leqno{(3)}
$$
de sorte que
\begin{align}
\mathcal{G} &= \mathcal{G}(0) \cdot \mathfrak{S}^{+\wedge}_{0,3} \qquad \text{(quoique sous-disjoint)} \leqno{(4)}\\
\mathcal{G}[0] &= \mathcal{G}(0) \cdot L_0^{\mathbb{C}} \leqno{(5)}\\
\mathcal{G}[0] &\cap \mathfrak{S}^{+\wedge}_{0,3} = L_0^{\mathbb{C}} \leqno{(6)}
\end{align}

On a posé
$$
L_0^{\mathbb{C}} = \text{sous-groupe fermé de } \mathfrak{S}^{+\wedge}_{0,3} \text{ engendré} \leqno{(7)}
$$
à un isomorphisme de $\simeq L_1^{\mathbb{C}}, L_\infty^{\mathbb{C}}$.

Considérons un groupe profini $M$, et un homomorphisme surjectif (continu)
$$
\varphi : \mathcal{G} \longrightarrow M. \leqno{(8)}
$$
On pose
$$
\begin{cases}
\varphi(\mathfrak{S}^{+\wedge}_{0,3}) = \mathbb{G} & \text{sous-groupe distingué de } M \\
\varphi(\mathcal{G}(0)) = M(0) \\
\varphi(\mathcal{G}[0]) = M[0] \\
\varphi(L_0^{\mathbb{C}}) = L_0^{\mathbb{C}}.
\end{cases} \leqno{(9)}
$$

Donc on aura ces sous-groupes fermés de $M$, satisfaisant
\begin{align}
M(0) &\subset M[0] \subset \operatorname{Norm}_M(L_0) \leqno{(10)}\\
L_0 &\subset \mathbb{G} \cap M[0]. \leqno{(11)}
\end{align}

Pour énoncer le gros théorème, on désignera comme d'habitude par $\rho, \sigma, \varepsilon_1, \varepsilon_\infty$ les images dans $\mathbb{G}$ des éléments de même nom dans $\mathfrak{S}^{+\wedge}_{0,3}$, qui y satisfont à les relations connues dans $\mathfrak{S}^{+\wedge}_{0,3}$, en particulier
$$
\sigma^2 = \rho^3 = 1, \quad \sigma\rho = \varepsilon_0, \quad \rho^\sigma = \varepsilon_1, \quad \varepsilon_1 = \sigma(\varepsilon_0) = \rho(\varepsilon_0). \leqno{(12)}
$$

Les restrictions des applications $\alpha_0, \beta_0$ de $(2, 2')$ à $\mathcal{M}_{\rho,\sigma}[0]$ seront plutôt notées $\alpha, \beta$, où $\alpha, \beta$ sont en fait des applications
$$
S\mathcal{G} \defeq \underset{\text{image de } \mathcal{G}}{\underbrace{\text{stabilisateur de } L_0, \text{ i.e.\ }\mathcal{G}}} \xrightrightarrows[\beta]{\alpha} \mathfrak{S}^{+\wedge}_{0,3} \leqno{(13)}
$$
$$
= \{(u,f) \in \mathcal{G} \times \mathfrak{S}^{+\wedge}_{0,3} \mid f u \in \mathcal{G}[0]\}
$$
dont on regarde les restrictions au sous-groupe ($\simeq \mathcal{M}_{\rho,\sigma}[0]$) de $S\mathcal{G}$ défini par la relation $f = 1$. Composant avec $p : \mathcal{G}[0] \rightrightarrows \mathfrak{S}^{+\wedge}_{0,3}$ avec $\varphi|\mathfrak{S}^{+\wedge}_{0,3}$, on trouve des applications, encore notées $\alpha, \beta$ (i.e.\ $\alpha^M, \beta^M$ si une confusion possible)
$$
\mathcal{G}[0] \xrightrightarrows[\beta]{\alpha} \mathbb{G} \leqno{(14)}
$$
satisfaisant à
$$
\begin{cases} u(\rho) = \operatorname{int}(\alpha) \rho \\ u(\sigma) = \operatorname{int}(\beta) \sigma \end{cases} \quad \text{pour } u \in M[0], \text{ d'image } \varphi(u_0), \text{ et } \alpha = \underline{\alpha}(u_0),\, \beta = \underline{\beta}(u_0). \leqno{(15)}
$$
